.glide-fade .glide__slides{margin-bottom:0;margin-top:0;transform:translateZ(0)!important}.glide-fade .glide__slide{left:0;margin-left:0!important;margin-right:0!important;opacity:0;order:2;position:absolute;top:0;transition:opacity .25s ease-in-out;will-change:contents}.glide-fade .glide__slide.glide__slide--active{opacity:1;order:1;position:relative;z-index:1}.glide-fade .glide__bullet:focus{outline:none}.glide-fade .glide__bullet--active,.glide-fade .glide__bullet:focus,.glide-fade .glide__bullet:hover{--tw-bg-opacity:1;background-color:rgb(255 255 255/var(--tw-bg-opacity))}.glide-fade .glide--swipeable{cursor:grab;cursor:-webkit-grab}.glide-fade .glide--dragging{cursor:grabbing;cursor:-webkit-grabbing}